def run(request, widget):
    df = get_cached_df(widget.dashboard, sheet_name='Ventas')
    df = apply_active_filters(df, request, widget)

    main_value = 0
    secondary_values = []
    main_label = "Total Ventas"

    if 'Ventas' in df.columns:
        # Ensure 'Ventas' column is numeric, coerce errors to NaN and drop them
        df['Ventas'] = pd.to_numeric(df['Ventas'], errors='coerce')
        df = df.dropna(subset=['Ventas'])

        main_value = df['Ventas'].sum()

        if 'Vendedor' in df.columns:
            # Group by 'Vendedor' and sum 'Ventas'
            sales_by_vendor = df.groupby('Vendedor')['Ventas'].sum().reset_index()

            # Sort by sales in descending order
            sales_by_vendor = sales_by_vendor.sort_values(by='Ventas', ascending=False)

            for _, row in sales_by_vendor.iterrows():
                secondary_values.append({
                    "label": row['Vendedor'],
                    "value": row['Ventas']
                })

    return JsonResponse({
        "main_value": main_value,
        "main_label": main_label,
        "secondary_values": secondary_values
    })

def run(request, widget):
    df = get_cached_df(widget.dashboard)
    df = apply_active_filters(df, request, widget)

    # Convert 'Ventas' to numeric, coercing errors to NaN
    if 'Ventas' in df.columns:
        df['Ventas'] = pd.to_numeric(df['Ventas'], errors='coerce')
    else:
        # Handle case where 'Ventas' column is missing
        return JsonResponse({
            "main_value": 0,
            "main_label": "Ventas (columna 'Ventas' no encontrada)",
            "secondary_values": []
        })

    # Drop rows where 'Ventas' is NaN (after conversion)
    df_cleaned = df.dropna(subset=['Ventas'])

    if not df_cleaned.empty and 'Tienda' in df_cleaned.columns:
        # Group by 'Tienda' and sum 'Ventas'
        sales_by_store = df_cleaned.groupby('Tienda')['Ventas'].sum()

        if not sales_by_store.empty:
            # Find the store with the highest sales
            top_store = sales_by_store.idxmax()
            max_sales = sales_by_store.max()

            return JsonResponse({
                "main_value": max_sales,
                "main_label": f"Ventas de {top_store}",
                "secondary_values": []
            })

    # Default return if no data or columns are missing
    return JsonResponse({
        "main_value": 0,
        "main_label": "Sin datos de ventas",
        "secondary_values": []
    })

def run(request, widget):
    df = get_cached_df(widget.dashboard, sheet_name='Respuestas de formulario 1')
    df = add_nivel_column(df)
    df = apply_active_filters(df, request, widget)

    columna_categoria = 'Escuela a la que pertenece'

    if columna_categoria not in df.columns:
        return JsonResponse({"columns": [], "rows": []})

    # Calcular la frecuencia de cada escuela
    counts = df[columna_categoria].value_counts().reset_index()
    counts.columns = [columna_categoria, 'Cantidad']

    # Calcular el porcentaje
    total_registros_sum = counts['Cantidad'].sum()
    if total_registros_sum > 0:
        counts['Porciento'] = (counts['Cantidad'] / total_registros_sum * 100).round(2).astype(str) + '%'
    else:
        counts['Porciento'] = '0.00%' # Si no hay registros, el porcentaje es 0

    # Aplicar _truncar a los nombres de las escuelas si son demasiado largos
    counts[columna_categoria] = counts[columna_categoria].apply(_truncar)

    # Preparar el formato para JsonResponse
    columns = [
        {"title": columna_categoria, "field": columna_categoria},
        {"title": "Cantidad", "field": "Cantidad", "hozAlign": "right"},
        {"title": "Porciento", "field": "Porciento", "hozAlign": "right"}
    ]

    rows = counts.to_dict('records')

    # Añadir la fila de Total
    total_row = {
        columna_categoria: 'Total',
        'Cantidad': total_registros_sum,
        'Porciento': '100.00%' if total_registros_sum > 0 else '0.00%'
    }
    rows.append(total_row)

    return JsonResponse({"columns": columns, "rows": rows})

def run(request, widget):
    df = get_cached_df(widget.dashboard, sheet_name='Respuestas de formulario 1')
    df = apply_active_filters(df, request, widget)

    columna_analizar = 'Escuela a la que pertenece'

    if columna_analizar not in df.columns:
        return JsonResponse({"series": [], "categories": []})

    # Valores a excluir, consistentes con las funciones compartidas
    excluir_valores = {"no se utiliza", "no aplica", "n/a", "", "nan", "none", "nat"}

    # Preprocesar la columna para el análisis
    # Convertir a string, limpiar espacios, y luego filtrar valores nulos o excluidos
    temp_series = df[columna_analizar].astype(str).str.strip()

    # Filtrar valores excluidos (insensible a mayúsculas/minúsculas)
    temp_series_filtered = temp_series[~temp_series.str.lower().isin(excluir_valores)]

    # Contar ocurrencias de cada categoría
    counts = temp_series_filtered.value_counts()

    if counts.empty:
        return JsonResponse({"series": [], "categories": []})

    # Preparar los datos en el formato requerido para chart_type="donut"
    # Las categorías son los índices de los counts (nombres de las escuelas)
    # Los datos son las cantidades contadas, como se pidió explícitamente.

    # Asegurarse de que los labels (categories) se truncan para la visualización
    categories = [_truncar(label) for label in counts.index.tolist()]
    data_values = counts.tolist()

    response_data = {
        "series": [{"name": "Cantidad", "data": data_values}], # Nombre de la serie indica que son cantidades
        "categories": categories
    }

    return JsonResponse(response_data)

def run(request, widget):
    df = get_cached_df(widget.dashboard, sheet_name='Respuestas de formulario 1')

    # Aplicar la función compartida para agregar la columna 'Nivel'
    df = add_nivel_column(df)

    # Aplicar los filtros activos del tablero
    df = apply_active_filters(df, request, widget)

    if df.empty:
        return JsonResponse({"columns": [], "rows": []})

    # Agrupar por 'Recinto:' y calcular Cantidad
    grouped_df = df.groupby('Recinto:').size().reset_index(name='Cantidad')

    # Calcular el total para el porcentaje
    total_cantidad = grouped_df['Cantidad'].sum()

    # Calcular Porciento, evitando el error de serialización de int64
    if total_cantidad > 0:
        grouped_df['Porciento'] = (grouped_df['Cantidad'] / total_cantidad * 100).round(2).astype(str) + '%'
    else:
        grouped_df['Porciento'] = '0.00%' # Manejar el caso de total_cantidad = 0

    # Preparar las columnas para el widget de tabla
    columns = [
        {"title": "Recinto", "field": "Recinto:"},
        {"title": "Cantidad", "field": "Cantidad"},
        {"title": "Porciento", "field": "Porciento"}
    ]

    # Preparar las filas para el widget de tabla
    rows = grouped_df.to_dict(orient="records")

    # Agregar la fila de total
    total_row = {
        "Recinto:": "Total",
        "Cantidad": total_cantidad,
        "Porciento": "100.00%"
    }
    rows.append(total_row)

    return JsonResponse({
        "columns": columns,
        "rows": rows
    })

